import{_ as t,o as a,c as l,ag as i}from"./chunks/framework.DTiDeF2Q.js";const f=JSON.parse('{"title":"Modern Tooling Aliase | Dotfiles (DE)","titleTemplate":":title","description":"Moderne Shell-Aliase fuer eza, bat und ripgrep. Ersetzen Sie klassische Unix-Tools durch schnellere Rust-basierte Alternativen.","frontmatter":{"title":"Modern Tooling Aliase | Dotfiles","description":"Moderne Shell-Aliase fuer eza, bat und ripgrep. Ersetzen Sie klassische Unix-Tools durch schnellere Rust-basierte Alternativen.","lang":"de-DE","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Modern Tooling Aliase preview","canonical":"/de/aliases/modern/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Modern Tooling Aliase","pageType":"docs","schemaType":"WebPage","metaTitle":"Modern Tooling Aliase - Dotfiles (DE)","permalink":"/de/aliases/modern/","sidebar":true,"meta":[{"name":"keywords","content":"moderne aliase, eza, bat, ripgrep, rust cli tools, dotfiles, shell"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Modern Tooling Aliase - Dotfiles"},{"name":"twitter:description","content":"Moderne Shell-Aliase fuer eza, bat und ripgrep als Ersatz fuer klassische Unix-Tools."},{"name":"og:title","content":"Modern Tooling Aliase - Dotfiles"},{"name":"og:description","content":"Moderne Shell-Aliase fuer eza, bat und ripgrep als Ersatz fuer klassische Unix-Tools."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"de_DE"}]},"headers":[],"relativePath":"de/aliases/modern/index.md","filePath":"de/aliases/modern/index.md","lastUpdated":1773010926000}'),n={name:"de/aliases/modern/index.md"};function o(s,e,d,r,c,h){return a(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="modern-tooling-aliase" tabindex="-1">Modern Tooling Aliase <a class="header-anchor" href="#modern-tooling-aliase" aria-label="Permalink to &quot;Modern Tooling Aliase&quot;">​</a></h1><p>Schnellere, intelligentere Ersatztools fuer klassische Unix-Befehle.</p><h2 id="uebersicht" tabindex="-1">Uebersicht <a class="header-anchor" href="#uebersicht" aria-label="Permalink to &quot;Uebersicht&quot;">​</a></h2><p>Die modernen Aliase in <code>modern.aliases.sh</code> bieten Rust-basierte Alternativen zu traditionellen Unix-Tools. Diese Aliase werden automatisch von <code>chezmoi</code> geladen und fallen elegant auf Standardbefehle zurueck, wenn moderne Tools nicht verfuegbar sind.</p><h2 id="referenz" tabindex="-1">Referenz <a class="header-anchor" href="#referenz" aria-label="Permalink to &quot;Referenz&quot;">​</a></h2><h3 id="dateilisting-mit-eza" tabindex="-1">Dateilisting mit eza <a class="header-anchor" href="#dateilisting-mit-eza" aria-label="Permalink to &quot;Dateilisting mit eza&quot;">​</a></h3><p>Ersetzt <code>ls</code> wenn <code>eza</code> installiert ist.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ls</code></td><td style="text-align:left;"><code>eza --icons</code></td><td style="text-align:left;">Dateien mit Icons auflisten</td></tr><tr><td style="text-align:left;"><code>ll</code></td><td style="text-align:left;"><code>eza -alF</code></td><td style="text-align:left;">Langes Listenformat</td></tr><tr><td style="text-align:left;"><code>la</code></td><td style="text-align:left;"><code>eza -a</code></td><td style="text-align:left;">Alle Dateien einschliesslich versteckter auflisten</td></tr><tr><td style="text-align:left;"><code>lt</code></td><td style="text-align:left;"><code>eza --tree</code></td><td style="text-align:left;">Verzeichnisbaum anzeigen</td></tr></tbody></table><p>Faellt auf Standard-<code>ls</code> zurueck, wenn <code>eza</code> nicht installiert ist.</p><h3 id="dateiinhalte-mit-bat" tabindex="-1">Dateiinhalte mit bat <a class="header-anchor" href="#dateiinhalte-mit-bat" aria-label="Permalink to &quot;Dateiinhalte mit bat&quot;">​</a></h3><p>Ersetzt <code>cat</code> wenn <code>bat</code> installiert ist.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cat</code></td><td style="text-align:left;"><code>bat</code></td><td style="text-align:left;">Dateiinhalt mit Syntax-Highlighting anzeigen</td></tr></tbody></table><h3 id="suche-mit-ripgrep" tabindex="-1">Suche mit ripgrep <a class="header-anchor" href="#suche-mit-ripgrep" aria-label="Permalink to &quot;Suche mit ripgrep&quot;">​</a></h3><p>Ersetzt <code>grep</code> wenn <code>rg</code> installiert ist.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>grep</code></td><td style="text-align:left;"><code>rg</code></td><td style="text-align:left;">Dateiinhalte mit Ripgrep durchsuchen</td></tr></tbody></table>',15)])])}const u=t(n,[["render",o]]);export{f as __pageData,u as default};
